#if UNITY_EDITOR
using System;
using System.Collections.Generic;
using System.Globalization;
using System.Text;
using UnityEditor;
using UnityEditor.Build;
using UnityEditor.Build.Reporting;
using UnityEngine;

/// <summary>
/// Pré-processador de build (Task #25): corre automaticamente o mesmo conjunto
/// de validações do <see cref="GameDataValidatorWindow"/> antes de cada build.
/// Se forem encontrados ERROS, o build é cancelado com uma excepção (aparece no
/// Console como "Build failed"). AVISOS são logados mas não cancelam o build.
///
/// Para desactivar temporariamente (ex: build de emergência):
///   Menu "Animals > Desactivar Validação de Build"
///
/// Para reactivar:
///   Menu "Animals > Activar Validação de Build"
///
/// Nota: a chave de preferência (<see cref="DisabledPrefKey"/>) é por-projecto
/// (EditorPrefs), não vai para controlo de versão.
/// </summary>
public class GameDataValidatorBuildPreprocess : IPreprocessBuildWithReport
{
    private const string DisabledPrefKey = "Animals.BuildValidator.Disabled";

    // callbackOrder: -100 → corre antes de outros preprocessors (ex: addressables)
    public int callbackOrder => -100;

    [MenuItem("Animals/Desactivar Validação de Build")]
    private static void Disable()
    {
        EditorPrefs.SetBool(DisabledPrefKey, true);
        Debug.LogWarning("[GameDataValidator] Validação de build DESACTIVADA. Reactivar em Animals > Activar Validação de Build.");
    }

    [MenuItem("Animals/Activar Validação de Build")]
    private static void Enable()
    {
        EditorPrefs.DeleteKey(DisabledPrefKey);
        Debug.Log("[GameDataValidator] Validação de build activada.");
    }

    [MenuItem("Animals/Desactivar Validação de Build", true)]
    private static bool CanDisable() => !EditorPrefs.GetBool(DisabledPrefKey);

    [MenuItem("Animals/Activar Validação de Build", true)]
    private static bool CanEnable() => EditorPrefs.GetBool(DisabledPrefKey);

    public void OnPreprocessBuild(BuildReport report)
    {
        if (EditorPrefs.GetBool(DisabledPrefKey))
        {
            Debug.LogWarning("[GameDataValidator] Validação de build desactivada — a saltar.");
            return;
        }

        var errors   = new List<string>();
        var warnings = new List<string>();

        RunAllChecks(errors, warnings);

        foreach (var w in warnings)
            Debug.LogWarning($"[BuildValidator] {w}");

        if (errors.Count == 0)
        {
            Debug.Log($"[BuildValidator] Validação OK — {warnings.Count} aviso(s), 0 erros.");
            return;
        }

        var sb = new StringBuilder();
        sb.AppendLine($"[BuildValidator] Build cancelado — {errors.Count} erro(s) encontrado(s):");
        foreach (var e in errors)
            sb.AppendLine($"  • {e}");

        // Cancela o build: BuildFailedException é a forma oficial de abortar
        // num IPreprocessBuildWithReport sem crashar o Editor.
        throw new BuildFailedException(sb.ToString());
    }

    // ──────────────────────────────────────────────────────────────────────────
    // Toda a lógica de validação abaixo é mantida sincronizada com
    // GameDataValidatorWindow.Validate() — qualquer nova verificação deve ser
    // adicionada em ambos os sítios.
    // ──────────────────────────────────────────────────────────────────────────

    private static void RunAllChecks(List<string> errors, List<string> warnings)
    {
        CheckIds<AreaData>(a => a.areaId, "areaId", a => a.displayName, errors);
        CheckIds<AnimalFormData>(a => a.formId, "formId", a => a.displayName, errors);
        CheckIds<ItemData>(a => a.itemId, "itemId", a => a.displayName, errors);
        CheckIds<UpgradeData>(a => a.upgradeId, "upgradeId", a => a.displayName, errors);
        CheckIds<MissionData>(a => a.missionId, "missionId", a => a.displayName, errors);
        CheckIds<EmblemData>(a => a.emblemId, "emblemId", a => a.displayName, errors);
        CheckIds<WorldData>(a => a.worldId, "worldId", a => a.displayName, errors);
        CheckIds<ChallengeDefinition>(a => a.challengeId, "challengeId", a => a.displayName, errors);

        CheckGameDatabaseRegistration(errors, warnings);
        CheckCommonReferences(warnings);
        CheckChallengeVariables(errors);
        CheckShopItemMixup(warnings);
        CheckDeprecatedComponents(warnings);
    }

    // ── IDs vazios / duplicados ────────────────────────────────────────────────

    private static void CheckIds<T>(
        Func<T, string> getId,
        string fieldName,
        Func<T, string> getName,
        List<string> errors) where T : ScriptableObject
    {
        string typeName = typeof(T).Name;
        var seen = new Dictionary<string, string>();

        foreach (var asset in FindAssets<T>())
        {
            string id   = getId(asset);
            string path = AssetDatabase.GetAssetPath(asset);
            string label = !string.IsNullOrEmpty(getName(asset)) ? getName(asset) : asset.name;

            if (string.IsNullOrEmpty(id))
            {
                errors.Add($"{typeName}: \"{label}\" ({path}) tem '{fieldName}' vazio.");
                continue;
            }

            if (seen.TryGetValue(id, out var otherPath))
                errors.Add($"{typeName}: ID duplicado '{id}' em \"{path}\" e \"{otherPath}\".");
            else
                seen[id] = path;
        }
    }

    // ── Registo no GameDatabase ───────────────────────────────────────────────

    private static void CheckGameDatabaseRegistration(List<string> errors, List<string> warnings)
    {
        var db = GameDatabase.Instance;
        if (db == null)
        {
            warnings.Add("GameDatabase não encontrado em Assets/Resources/GameDatabase.asset — verificação de registo saltada.");
            return;
        }

        CheckRegistered(FindAssets<WorldData>(),       db.worlds,      "WorldData",       warnings);
        CheckRegistered(FindAssets<AreaData>(),        db.areas,       "AreaData",        warnings);
        CheckRegistered(FindAssets<AnimalFormData>(),  db.animalForms, "AnimalFormData",  warnings);
        CheckRegistered(FindAssets<ItemData>(),        db.items,       "ItemData",        warnings);
        CheckRegistered(FindAssets<UpgradeData>(),     db.upgrades,    "UpgradeData",     warnings);
        CheckRegistered(FindAssets<MissionData>(),     db.missions,    "MissionData",     warnings);
        CheckRegistered(FindAssets<EmblemData>(),      db.emblems,     "EmblemData",      warnings);
    }

    private static void CheckRegistered<T>(List<T> all, List<T> registered, string typeName, List<string> warnings)
        where T : ScriptableObject
    {
        foreach (var asset in all)
        {
            bool found = registered != null && registered.Contains(asset);
            if (!found)
                warnings.Add($"{typeName} \"{asset.name}\" ({AssetDatabase.GetAssetPath(asset)}) não está registado no GameDatabase.");
        }
    }

    // ── Referências comuns em falta ────────────────────────────────────────────

    private static void CheckCommonReferences(List<string> warnings)
    {
        foreach (var area in FindAssets<AreaData>())
        {
            if (area.world == null)
                warnings.Add($"AreaData \"{area.displayName}\" ({AssetDatabase.GetAssetPath(area)}) não tem 'world' atribuído.");
        }

        foreach (var emblem in FindAssets<EmblemData>())
        {
            if (string.IsNullOrEmpty(emblem.obtainedVariable))
                warnings.Add($"EmblemData \"{emblem.displayName}\" ({AssetDatabase.GetAssetPath(emblem)}) não tem 'obtainedVariable' — nunca será contado em GetTotalCompletionPercent.");
        }
    }

    // ── Variáveis de Desafio duplicadas ───────────────────────────────────────

    private static void CheckChallengeVariables(List<string> errors)
    {
        var seen = new Dictionary<string, string>();

        foreach (var challenge in FindAssets<ChallengeDefinition>())
        {
            if (string.IsNullOrEmpty(challenge.challengeId)) continue;

            string path = AssetDatabase.GetAssetPath(challenge);
            CheckVariable(challenge.ActiveVariable,    "ActiveVariable",    path, seen, errors);
            CheckVariable(challenge.CompletedVariable, "CompletedVariable", path, seen, errors);
        }
    }

    private static void CheckVariable(string name, string fieldLabel, string path,
        Dictionary<string, string> seen, List<string> errors)
    {
        if (string.IsNullOrEmpty(name)) return;

        if (seen.TryGetValue(name, out var otherPath))
            errors.Add($"ChallengeDefinition: variável '{name}' ({fieldLabel}) duplicada entre \"{path}\" e \"{otherPath}\".");
        else
            seen[name] = path;
    }

    // ── Task #13: BrotoDeVida vs SeivaVital em lojas ──────────────────────────

    /// <summary>
    /// Emite aviso se uma ShopData vender um item cujo ID ou nome contenha
    /// "broto" (case-insensitive). Segundo o GDD (linha 3601), o Broto de Vida
    /// é um DROP de chão — nunca deve aparecer em lojas. O item de cura
    /// instantânea vendido em lojas é a Seiva Vital (effectType = CuraInstantanea).
    /// </summary>
    private static void CheckShopItemMixup(List<string> warnings)
    {
        foreach (var shop in FindAssets<ShopData>())
        {
            if (shop.entries == null) continue;
            string shopPath = AssetDatabase.GetAssetPath(shop);

            foreach (var entry in shop.entries)
            {
                if (entry?.item == null) continue;

                string id   = entry.item.itemId ?? "";
                string name = entry.item.displayName ?? entry.item.name ?? "";

                bool looksLikeBroto =
                    id.IndexOf("broto", System.StringComparison.OrdinalIgnoreCase) >= 0 ||
                    name.IndexOf("Broto de Vida", System.StringComparison.OrdinalIgnoreCase) >= 0;

                if (looksLikeBroto)
                    warnings.Add(
                        $"[Task #13] ShopData \"{shop.shopName}\" ({shopPath}) vende \"{name}\" " +
                        $"(id: '{id}'). O Broto de Vida é um drop de chão e NÃO deve ser " +
                        "vendido em lojas (GDD linha 3601). Substitui pelo item Seiva Vital " +
                        "(effectType = CuraInstantanea).");
            }
        }
    }

    // ── Componentes obsoletos em prefabs ──────────────────────────────────────

    /// <summary>
    /// Task #5: SussurroDaTerraPickup contradiz o GDD (Sussurros não são pickups
    /// físicos) — emite aviso se o componente aparecer em qualquer prefab do projecto.
    /// Não abre cenas para não perturbar o fluxo de build; prefabs são suficientes
    /// para detectar usos acidentais.
    /// </summary>
    private static void CheckDeprecatedComponents(List<string> warnings)
    {
        foreach (var guid in AssetDatabase.FindAssets("t:Prefab"))
        {
            string path = AssetDatabase.GUIDToAssetPath(guid);
            var go = AssetDatabase.LoadAssetAtPath<GameObject>(path);
            if (go == null) continue;

            if (go.GetComponentInChildren<SussurroDaTerraPickup>(true) != null)
                warnings.Add(
                    $"[Obsoleto] Prefab \"{go.name}\" ({path}) contém SussurroDaTerraPickup. " +
                    "Segundo o GDD, Sussurros são comprados ao NPC Contador de Histórias — " +
                    "não são pickups físicos. Remove o componente e usa uma Action de diálogo.");
        }
    }

    // ── Util ──────────────────────────────────────────────────────────────────

    private static List<T> FindAssets<T>() where T : ScriptableObject
    {
        var result = new List<T>();
        foreach (var guid in AssetDatabase.FindAssets($"t:{typeof(T).Name}"))
        {
            var asset = AssetDatabase.LoadAssetAtPath<T>(AssetDatabase.GUIDToAssetPath(guid));
            if (asset != null) result.Add(asset);
        }
        return result;
    }
}
#endif
